@Test
public void shouldParseSingleCharacterShortOption() throws Exception {
    String[] singleShortOption = new String[] { "-a" };

    final CommandLine commandLine = parser.parse(options, singleShortOption);

    assertTrue(commandLine.hasOption("a"));
    assertFalse(commandLine.hasOption("b"));
    assertFalse(commandLine.hasOption("t1"));
}

@Test
public void shouldParseShortOptionWithValue() throws Exception {
    String[] shortOptionWithValue = new String[] { "-a=value" };

    final CommandLine commandLine = parser.parse(options, shortOptionWithValue);

    assertTrue(commandLine.hasOption("a"));
    assertEquals("value", commandLine.getOptionValue("a"));
}

@Test
public void shouldRejectInvalidConcatenatedOptions() throws Exception {
    String[] invalidConcatenated = new String[] { "-ax" };

    try {
        parser.parse(options, invalidConcatenated);
        fail("Expected ParseException for invalid concatenated option");
    } catch (ParseException e) {
        // Expected exception
    }
}

@Test
public void shouldParseTripleConcatenatedShortOptions() throws Exception {
    String[] tripleConcatenated = new String[] { "-abc" };

    final CommandLine commandLine = parser.parse(options, tripleConcatenated);

    assertTrue(commandLine.hasOption("a"));
    assertTrue(commandLine.hasOption("b"));
    assertTrue(commandLine.hasOption("c"));
    assertFalse(commandLine.hasOption("t1"));
}
